ALTER TABLE public.user_access_events DROP CONSTRAINT IF EXISTS user_access_events_event_check;
ALTER TABLE public.user_access_events ADD CONSTRAINT user_access_events_event_check CHECK (event IN ('ACCESS_CREATED','ACCESS_RENEWED','ACCESS_EXPIRED','PASSWORD_CHANGED','ACCOUNT_BLOCKED','LOGIN','MP_PREAPPROVAL_CREATED','MP_SUBSCRIPTION_ACTIVE','MP_SUBSCRIPTION_SUSPENDED'));